mapper.select:
SELECT *
  FROM TW_VACCIN

	   HOSP_CD = #{hospCd}

	   AND VACCIN_YEAR = #{vaccinYear}


	   AND VACCIN_TYPE = #{vaccinType}


 ORDER BY VACCIN_ID DESC

mapper.update:
UPDATE TW_VACCIN
   SET VACCIN_YEAR = #{vaccinYear}
     , VACCIN_TYPE = #{vaccinType}
     , VACCIN_NM = #{vaccinNm}
     , TARGET_CNT = #{targetCnt}
     , COMPLETE_CNT = #{completeCnt}
     , VACCIN_DT = #{vaccinDt}
     , REMARK = #{remark}
     , MOD_ID = #{modId}
     , MOD_DT = NOW()
 WHERE VACCIN_ID = #{vaccinId}

